INSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: The ___ is blue.', 'sky');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: I have two ___.', 'cats');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: She likes to eat ___.', 'apples');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: My ___ is John.', 'name');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: He is reading a ___.', 'book');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: They go to ___ every day.', 'school');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: Please close the ___.', 'door');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: I drink ___ in the morning.', 'coffee');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: The ___ is sleeping.', 'dog');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A1', 'Listen and complete: We play ___ on weekends.', 'tennis');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: I went to the ___ yesterday.', 'supermarket');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: She bought a new ___.', 'dress');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: My favorite season is ___.', 'summer');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: He was watching ___ last night.', 'television');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: The ___ departs at 9 AM.', 'train');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: We stayed in a nice ___.', 'hotel');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: They are planning a ___ to Paris.', 'trip');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: I need to buy some ___.', 'groceries');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: The ___ was very interesting.', 'movie');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'A2', 'Listen and complete: She is learning to play the ___.', 'guitar');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: The company is launching a new ___.', 'product');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: He received a ___ for his hard work.', 'promotion');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: They are discussing the new ___.', 'project');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: She has a lot of ___ in her field.', 'experience');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: We need to improve our ___ skills.', 'communication');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: The ___ of the meeting is at 3 PM.', 'beginning');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: He is looking for a new ___.', 'opportunity');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: The ___ was delayed due to weather.', 'flight');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: She gave a great ___ today.', 'presentation');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B1', 'Listen and complete: The ___ rate is decreasing.', 'unemployment');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The government announced a new ___.', 'policy');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The research requires careful ___.', 'analysis');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: They reached a mutual ___.', 'agreement');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The environmental ___ is severe.', 'impact');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: He emphasized the ___ of education.', 'importance');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: She has a very strong ___ in science.', 'background');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The new law will ___ next year.', 'implement');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: We must consider the long-term ___.', 'consequences');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The discovery was a major ___.', 'breakthrough');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'B2', 'Listen and complete: The ___ of the species is crucial.', 'preservation');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The paradox is inherently ___.', 'complex');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: Her argument was completely ___.', 'persuasive');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The economic ___ is quite unstable.', 'infrastructure');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: He provided an eloquent ___ of the theory.', 'explanation');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The legislation was deemed ___.', 'controversial');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: We need to mitigate the ___ risks.', 'potential');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The sheer ___ of the task is daunting.', 'magnitude');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The findings challenge the current ___.', 'paradigm');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: Her approach is highly ___.', 'unconventional');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('listening', 'C1', 'Listen and complete: The historical context is often ___.', 'overlooked');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A1', 'Complete: She ___ a teacher.', 'is', 'Use ''is'' for third-person singular (she, he, it).');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A1', 'Complete: I ___ from Spain.', 'am', 'Use ''am'' for first-person singular (I).');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A1', 'Complete: They ___ playing football.', 'are', 'Use ''are'' for plural subjects (they, we, you).');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A1', 'Complete: He ___ not like apples.', 'does', 'Use ''does'' for negative present simple third-person.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A1', 'Complete: We ___ a new car.', 'have', 'Use ''have'' for ''we'' in present simple.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A2', 'Complete: I ___ to the cinema yesterday.', 'went', 'Past simple of ''go'' is ''went''.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A2', 'Complete: She ___ English for two years.', 'studied', 'Past simple of ''study'' is ''studied''.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A2', 'Complete: They ___ dinner when I arrived.', 'were', 'Past continuous: ''were'' + playing/doing.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A2', 'Complete: He has ___ finished his homework.', 'already', '''Already'' is used in present perfect for completed actions.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'A2', 'Complete: If it rains, we ___ stay home.', 'will', 'First conditional uses ''will'' + base verb.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B1', 'Complete: I have ___ been to Japan.', 'never', 'Use ''never'' for experiences you haven''t had.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B1', 'Complete: She ___ have forgotten about the meeting.', 'must', '''Must have'' expresses strong probability in the past.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B1', 'Complete: If I ___ you, I wouldn''t do that.', 'were', 'Second conditional uses ''were'' for all subjects in the ''if'' clause.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B1', 'Complete: The letter was ___ by John.', 'written', 'Passive voice uses the past participle (''written'').');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B1', 'Complete: He asked me where I ___ going.', 'was', 'Reported speech shifts present continuous to past continuous.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B2', 'Complete: Had I known, I ___ have helped you.', 'would', 'Third conditional: ''would have'' + past participle.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B2', 'Complete: Despite ___ tired, she kept working.', 'being', '''Despite'' is followed by a gerund (-ing) or noun.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B2', 'Complete: It''s high time we ___.', 'left', '''It''s high time'' is followed by the past simple.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B2', 'Complete: Not only ___ he late, but he was also rude.', 'was', 'Inversion is used after ''Not only'' at the beginning of a sentence.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'B2', 'Complete: The project is ___ to be completed by May.', 'expected', 'Passive construction for expectations.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'C1', 'Complete: Scarcely ___ I arrived when the phone rang.', 'had', 'Inversion with past perfect after ''Scarcely''.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'C1', 'Complete: She is ___ to have resigned.', 'rumored', 'Passive reporting structure.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'C1', 'Complete: But for your help, I ___ have failed.', 'would', '''But for'' + noun means ''if it hadn''t been for''.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'C1', 'Complete: Try as he ___, he couldn''t open the door.', 'might', '''Try as he might'' is a concession clause.');\nINSERT INTO public.exercises (type, level, prompt, answer, grammar_info) VALUES ('writing', 'C1', 'Complete: It is imperative that he ___ present.', 'be', 'Subjunctive mood after ''imperative that''.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A1', 'Read aloud: What is your name?', 'What is your name?');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A1', 'Read aloud: I live in a big house.', 'I live in a big house.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A1', 'Read aloud: My favorite color is red.', 'My favorite color is red.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A1', 'Read aloud: I like to eat pizza.', 'I like to eat pizza.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A1', 'Read aloud: The cat is on the table.', 'The cat is on the table.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A2', 'Read aloud: What did you do last weekend?', 'What did you do last weekend?');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A2', 'Read aloud: I usually wake up at seven o''clock.', 'I usually wake up at seven o''clock.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A2', 'Read aloud: The weather is very nice today.', 'The weather is very nice today.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A2', 'Read aloud: I want to travel to London.', 'I want to travel to London.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'A2', 'Read aloud: She is wearing a blue jacket.', 'She is wearing a blue jacket.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B1', 'Read aloud: In my opinion, learning English is important.', 'In my opinion, learning English is important.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B1', 'Read aloud: I have been working here for two years.', 'I have been working here for two years.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B1', 'Read aloud: Could you please tell me the way to the station?', 'Could you please tell me the way to the station?');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B1', 'Read aloud: I would rather stay home tonight.', 'I would rather stay home tonight.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B1', 'Read aloud: Technology has changed our lives significantly.', 'Technology has changed our lives significantly.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B2', 'Read aloud: The environmental impact of plastic is a major concern.', 'The environmental impact of plastic is a major concern.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B2', 'Read aloud: I completely agree with your point of view.', 'I completely agree with your point of view.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B2', 'Read aloud: It is essential to maintain a healthy work-life balance.', 'It is essential to maintain a healthy work-life balance.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B2', 'Read aloud: Furthermore, the economic implications are profound.', 'Furthermore, the economic implications are profound.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'B2', 'Read aloud: Despite the challenges, we managed to succeed.', 'Despite the challenges, we managed to succeed.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'C1', 'Read aloud: The underlying premise of this argument is fundamentally flawed.', 'The underlying premise of this argument is fundamentally flawed.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'C1', 'Read aloud: We must address the systemic inequalities prevalent in society.', 'We must address the systemic inequalities prevalent in society.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'C1', 'Read aloud: Her eloquent speech resonated deeply with the audience.', 'Her eloquent speech resonated deeply with the audience.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'C1', 'Read aloud: It is highly probable that the paradigm will shift entirely.', 'It is highly probable that the paradigm will shift entirely.');\nINSERT INTO public.exercises (type, level, prompt, answer) VALUES ('speaking', 'C1', 'Read aloud: Consequently, the mitigation strategies proved to be inadequate.', 'Consequently, the mitigation strategies proved to be inadequate.');